+    private async Task HandleNext()
+    {
+        _errorMessage = null;
+
+        // Cancel any in-flight validation before starting a new one.
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = new CancellationTokenSource();
+        var token = _cts.Token;
+
+        _isValidating = true;
+
+        try
